  // live in the Resolution config block (v13.21 — all res knobs in one place).
  var TERRAIN_CHUNK_CACHE_LIMIT = 180;
  var TERRAIN_CHUNK_REBUILDS_PER_FRAME = 1;

  // ============================================================
  // TILE DETAIL ATLAS
  // Pre-renders the expensive per-tile clod/chip detail into 16
