    if (!uiTopCanvas) return;
    uiTopCanvas.style.left   = '0';
    uiTopCanvas.style.top    = '0';
    uiTopCanvas.style.width  = viewW + 'px';
    uiTopCanvas.style.height = viewH + 'px';
