    gl.uniform1f(skyGLU.uMulti, sg.multi);
    gl.uniform1f(skyGLU.uGain, sg.gain);
    gl.uniform1f(skyGLU.uFloor, sg.floor);
    gl.uniform1f(skyGLU.uContrast, sg.contrast);
    gl.uniform1f(skyGLU.uRadial, sg.radial);
