      ironStripBolt:   '#5a5550',
      beamWood:        '#5a3a22',
      beamWoodHi:      '#7a5028',
      beamWoodLo:      '#2a1810',
      beamIron:        '#1f1812',
      beamIronHi:      '#3a3530',
      bannerBg:        '#7a4828',
      bannerBgHi:      '#9c6438',
      bannerBgLo:      '#4a2818',
      bannerFrame:     '#5a3a22',
      stencilWarm:     '#f0d088',
      stencilCool:     '#1a0e08',
      pegboard:        '#7a5828',
      pegboardHole:    '#3a2810',
      pegboardFrame:   '#5a3a22',
      shelfDark:       '#2a1810',
      shelfWood:       '#5a3a22',
      shelfWoodHi:     '#8a6438',
      flagRed:         '#d4a838',   // sheriff gold star uses this
      flagRedHi:       '#f0d088',
      flagGold:        '#9c7838',
      flagPole:        '#3a3530',
      lampShade:       '#1a1612',
      lampShadeHi:     '#3a3530',
