      for (var k = 0; k <= 9; k++) { setCell(g, 10 + k, 6 + k, shade(PAPER, 0.32)); setCell(g, 10 + k, 25 - k, shade(PAPER, 0.32)); }
      setCell(g, 10, 6, PAPER[4]);
