    capPx(x + 5, y + h - 9, w - 10, 3, CAP.bDark); capPx(x + 6, y + h - 9, w - 12, 2, CAP.bMid); capPx(x + 6, y + h - 9, w - 12, 1, CAP.bHi); drawBrassBolt(cx, y + h - 8);
