    var cx = x + (w >> 1);
    capPx(x + 1, y + 1, 3, h - 2, CAP.ironBase); capPx(x + 1, y + 1, 1, h - 2, CAP.ironHi); capPx(x + 4, y + 1, 1, h - 2, CAP.ironDark);
