    capStar(cx + 1, y + 10, 3, CAP.redBase, CAP.redBright);
    for (var ry = y + 22; ry < y + h - 18; ry += 12) { drawConsoleRivet(x + 8, ry); drawConsoleRivet(x + w - 9, ry); }
