    capPx(x + 7, y + 3, 1, h - 6, CAP.outline); capPx(x + 8, y + 3, 1, h - 6, CAP.bHi);
    capPx(x + 15, y + 5, 1, h - 10, CAP.outline); capPx(x + 16, y + 5, 1, h - 10, CAP.bHi); capPx(x + 17, y + 5, 1, h - 10, CAP.bDark);
