    capShell(x, y, w, h);
    capPx(x + 3, y + 3, w - 6, 1, CAP.bMid); capPx(x + 3, y + h - 4, w - 6, 1, CAP.bMid);
    capPx(x + 3, y + 3, 1, h - 6, CAP.bMid); capPx(x + w - 4, y + 3, 1, h - 6, CAP.bMid);
