    ctx.fillRect(x + 4, brassY, w - 8, 12);
    ctx.fillStyle = '#7a5a2c';
    ctx.fillRect(x + 5, brassY + 1, w - 10, 10);
    ctx.fillStyle = '#a07c40';
    ctx.fillRect(x + 5, brassY + 1, w - 10, 1);
    ctx.fillStyle = '#4f3a1b';
