    // non-Newtonian damping (JELLO_SHEAR). Cheap, so compute it always.
    var e00 = T00 - R00, e01 = T01 - R01, e10 = T10 - R10, e11 = T11 - R11;
    var strain = Math.sqrt(e00 * e00 + e01 * e01 + e10 * e10 + e11 * e11);
