    for (k = 0; k < rn; k++) {
      kp = k + 1; if (kp === rn) kp = 0;
      ip = ring[kp]; im = ring[km];
      gx = 0.5 * (py[ip] - py[im]) * sign;
      gy = 0.5 * (px[im] - px[ip]) * sign;
      sg += gx * gx + gy * gy;
      km = k;
    }
    if (sg < 1e-9) return;
