            'jello.JELLO_DAMPING': 0.99, 'jello.JELLO_INT_DAMP': 50, 'jello.JELLO_VMAX': 350, 'jello.JELLO_SLEEP_VSQ': 15, 'jello.JELLO_XPBD_SUBSTEPS': 10,
            'jello.JELLO_INFLATE': 1.0, 'jello.JELLO_GRAVITY': 950, 'jello.JELLO_BOUNCE': 0.1
